import (
	"context"
	"fmt"

	"github.com/openmeterio/openmeter/openmeter/customer"
	"github.com/openmeterio/openmeter/pkg/framework/transaction"
	"github.com/openmeterio/openmeter/pkg/models"
)

func (s *Service) ArchiveCustomer(ctx context.Context, input customer.ArchiveCustomerInput) (*customer.Customer, error) {
	if err := s.requestValidatorRegistry.ValidateUpdateCustomer(ctx, customer.UpdateCustomerInput{
		CustomerID: input.CustomerID,
	}); err != nil {
		return nil, models.NewGenericValidationError(err)
	}

	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (*customer.Customer, error) {
		cus, err := s.adapter.GetCustomer(ctx, customer.GetCustomerInput{CustomerID: &input.CustomerID})
		if err != nil {
			return nil, fmt.Errorf("failed to get customer: %w", err)
		}

		if err = s.hooks.PreUpdate(ctx, cus); err != nil {
			return nil, err
		}

		cus, err = s.adapter.ArchiveCustomer(ctx, input)
		if err != nil {
			return nil, fmt.Errorf("failed to archive customer: %w", err)
		}

		if err = s.hooks.PostUpdate(ctx, cus); err != nil {
			return nil, err
		}

		if err := s.publisher.Publish(ctx, customer.NewCustomerUpdateEvent(ctx, cus)); err != nil {
			return nil, fmt.Errorf("failed to publish customer updated event: %w", err)
		}

		return cus, nil
	})
}
